from functools import lru_cache

def largest_subset(nums):
    n = len(nums)

    @lru_cache(maxsize=None)
    def dp(i, prev):
        if i >= n:
            return 0
        ans = dp(i + 1, prev)
        if nums[i] % prev == 0:
            ans = max(ans, 1 + dp(i + 1, nums[i]))
        return ans

    return dp(0, -1) + 1

